import os
from curl_cffi import requests

# Même cookie qu'avant
COOKIES_RAW = "Edition=%7B%22code%22%3A%22WALS00%22%2C%22label%22%3A%22Edition%20nationale%22%2C%22url%22%3A%22%2F%22%7D; didomi_; euconsent-v2=CQdmyUAQdmyUAAHABBENCMFsAP_gAABAAAAALAFB7C7fSWFjeTJnYPpEaQBcwVAKokAhBACJAQgBiBoEIJQQlmAKIATAAKAKABAAgERAAQBhCABAAACAAIABISAEIAAQIQAAIqAEAAARAwAACBhBGwEAEAAQgEAQAAEAgAMAAAqAQFBAAYAgBEAQAAAhAACFAAAAADAgAAAAAAAAAggAAAAAIAIAEAEEAFAAEABAAAEAAAAAAAAAAAAAAAAAAAAAAAAgAAAAAAAAAAAABADiACADgAYpABgACC-JKADAAEF8R0AGAAIL4kIAMAAQXxCQAYAAgviWgAwABBfE.f_wAAAgAAAAA; firstid=dc56b25855964f238eddb4a45f565358; .XCONNECT_; .XCONNECT=2=1; consentTrackingPub=1"

cookies = {}
for part in COOKIES_RAW.split(';'):
    if '=' in part:
        key, value = part.strip().split('=', 1)
        cookies[key] = value

def download(url, filename):
    print(f"Downloading {url}...")
    try:
        r = requests.get(url, cookies=cookies, impersonate="chrome120")
        with open(filename, "w", encoding="utf-8") as f:
            f.write(r.text)
    except Exception as e:
        print(f"Erreur: {e}")

# URL 1: mag.mulhouse
download("https://mag.mulhouse-alsace.fr/agenda/hamlet-2/", "debug_mag.html")

